import React, { useEffect, useState } from 'react';
import Office from '../../../assets/images/office.png';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faCalendarCheck, faAngleUp } from '@fortawesome/free-solid-svg-icons';
import { useNavigate } from 'react-router-dom';
import '../../../../styles/Hero.css';
import { isMobile } from 'react-device-detect';

function Hero() {
	const navigate = useNavigate();
	const [goUp, setGoUp] = useState(false);

	const scrollToTop = () => {
		window.scrollTo({ top: 0, behavior: 'smooth' });
	};

	const handleBookAppointmentClick = () => {
		navigate('/appointment');
	};

	useEffect(() => {
		const onPageScroll = () => {
			if (window.scrollY > 600) {
				setGoUp(true);
			} else {
				setGoUp(false);
			}
		};
		window.addEventListener('scroll', onPageScroll);

		return () => {
			window.removeEventListener('scroll', onPageScroll);
		};
	}, []);

	return (
		<div className="section-container">
			<div className="hero-section">
			{isMobile && <img className="hero-image2" src={Office} alt="Office" style={{height: 'auto',position:'absolute', top:'36%'}} />}
				<div className="text-section">
					<p className="text-headline">{`Apps development, technology and security with a lasting impact`}</p>
					<h2 className="text-title">{`Make an appointment`}</h2>
					<p className="text-descritpion">{`Talk to us and allow us to provide you with our technical expertise and solutions.`}</p>
					<button className="text-appointment-btn" type="button" onClick={handleBookAppointmentClick}>
						<FontAwesomeIcon icon={faCalendarCheck} /> {`Book Appointment`}
					</button>
					<div className="text-stats">
						{/* <div className="text-stats-container">
							<p>1+</p>
							<p>Clients</p>
						</div>

						<div className="text-stats-container">
							<p>10+</p>
							<p>Expert Consultants</p>
						</div>

						<div className="text-stats-container">
							<p>20+</p>
							<p>Years of Professional Experience</p>
						</div> */}
					</div>
				</div>
				<div className="hero-image-section">
					<img className="hero-image1" src={Office} alt="Office" />
				</div>
			</div>

			<div onClick={scrollToTop} className={`scroll-up ${goUp ? 'show-scroll' : ''}`}>
				<FontAwesomeIcon icon={faAngleUp} />
			</div>
		</div>
	);
}

export default Hero;
